	(1, 1, 1, 0, 0, 1, 0, 0, 'Page', '2026-04-09 14:39:32', '2026-04-09 14:39:32', 'Inherit', 'Inherit', 'home', 'Home', NULL, '<p>Welcome to Silverstripe! This is the default homepage. You can edit this page by opening <a href="admin/">the CMS</a>.</p><p>For comprehensive information on Silverstripe CMS, see the <a target="_blank" href="http://docs.silverstripe.org">developer documentation</a>.</p>', NULL, NULL, 1, 1, 1, 0, 0, NULL, 0),
	(2, 1, 2, 1, 0, 1, 0, 0, 'Page', '2026-04-09 14:39:32', '2026-04-09 14:39:32', 'Inherit', 'Inherit', 'home', 'Home', NULL, '<p>Welcome to Silverstripe! This is the default homepage. You can edit this page by opening <a href="admin/">the CMS</a>.</p><p>For comprehensive information on Silverstripe CMS, see the <a target="_blank" href="http://docs.silverstripe.org">developer documentation</a>.</p>', NULL, NULL, 1, 1, 1, 0, 0, NULL, 0),
